from collections import deque

def bfs(graph, start):
    """Return nodes in BFS order starting from start."""
    visited = {start}
    queue = deque([start])
    traversal = []
    while queue:
        node = queue.popleft()
        traversal.append(node)
        for neighbour in graph.get(node, []):
            if neighbour not in visited:
                visited.add(neighbour)
                queue.append(neighbour)
    return traversal

